import sys

input = sys.stdin.read
data = input().split()

N = int(data[0])
A = list(map(int, data[1:]))

l = 0
r = N - 1
prev = -1
moves = 0

while l <= r:
    left_ok = A[l] > prev
    right_ok = A[r] > prev
    if not left_ok and not right_ok:
        break
    moves += 1
    if not left_ok:
        prev = A[r]
        r -= 1
    elif not right_ok:
        prev = A[l]
        l += 1
    else:
        if A[l] > A[r]:
            prev = A[l]
            l += 1
        elif A[r] > A[l]:
            prev = A[r]
            r -= 1
        else:
            if l == r:
                prev = A[l]
                l += 1
            else:
                lnext = A[l + 1]
                rnext = A[r - 1]
                if lnext < rnext:
                    prev = A[l]
                    l += 1
                elif rnext < lnext:
                    prev = A[r]
                    r -= 1
                else:
                    prev = A[l]
                    l += 1

if moves % 2 == 1:
    print("Alice")
else:
    print("Bob")

